// Connect to apcupsd TCP status port
const net = require('net');
const UPS_HOST = process.env.UPS_HOST || '10.0.0.1';
const UPS_PORT = parseInt(process.env.UPS_PORT || '3551');

function readApcupsd() {
  return new Promise((resolve, reject) => {
    const client = net.createConnection(UPS_PORT, UPS_HOST, () => {
      // apcupsd status command: 6-byte header + 'status'
      const cmd = Buffer.alloc(8);
      cmd.writeUInt16BE(6, 0);
      cmd.write('status', 2);
      client.write(cmd);
    });

    let data = Buffer.alloc(0);
    client.on('data', chunk => { data = Buffer.concat([data, chunk]); });
    client.on('end', () => resolve(data.toString('ascii')));
    client.on('error', reject);
    setTimeout(() => { client.destroy(); reject(new Error('apcupsd timeout')); }, 5000);
  });
}

try {
  const raw = await readApcupsd();
  const lines = raw.split('\n').filter(l => l.trim());
  const kv = {};
  for (const line of lines) {
    const idx = line.indexOf(':');
    if (idx > 0) kv[line.slice(0, idx).trim()] = line.slice(idx + 1).trim();
  }

  const status   = kv['STATUS']   || 'UNKNOWN';
  const bcharge  = kv['BCHARGE']  || '?';
  const loadpct  = kv['LOADPCT']  || '?';
  const timeleft = kv['TIMELEFT'] || '?';
  const model    = kv['MODEL']    || 'UPS';

  return `${model}: ${status} | Battery ${bcharge} | Load ${loadpct} | Runtime ${timeleft}`;
} catch (err) {
  return `UPS check failed: ${err.message}`;
}

function httpGet(url, headers = {}) {
  return new Promise((resolve, reject) => {
    const parsed = new (require('url').URL)(url);
    const lib = parsed.protocol === 'https:' ? require('https') : require('http');
    const options = {
      hostname: parsed.hostname,
      port: parsed.port || (parsed.protocol === 'https:' ? 443 : 80),
      path: parsed.pathname + parsed.search,
      method: 'GET',
      headers,
      timeout: 10000
    };
    const req = lib.request(options, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); }
        catch (e) { reject(new Error('JSON parse error: ' + data.slice(0,120))); }
      });
    });
    req.on('error', reject);
    req.on('timeout', () => { req.destroy(); reject(new Error('request timed out')); });
    req.end();
  });
}

const netboxUrl = process.env.NETBOX_URL || 'https://netbox.galaxy.rip';
const token = process.env.NETBOX_TOKEN || '';
const query = ($parameter.query || '').trim();
const type  = ($parameter.type  || 'auto').toLowerCase();

const headers = {
  'Authorization': `Token ${token}`,
  'Accept': 'application/json'
};

async function nbGet(path) {
  try {
    return await httpGet(`${netboxUrl}/api/${path}`, headers);
  } catch (e) {
    return null;
  }
}

const results = [];

try {
  const isIp     = /^\d{1,3}\.\d{1,3}\.\d{1,3}/.test(query);
  const isPrefix = isIp && query.includes('/');

  if (type === 'auto' || type === 'ips' || (isIp && !isPrefix)) {
    const data = await nbGet(`ipam/ip-addresses/?address=${encodeURIComponent(query)}&limit=10`);
    for (const ip of (data?.results || [])) {
      const dev   = ip.assigned_object?.device?.name || ip.assigned_object?.virtual_machine?.name || '';
      const iface = ip.assigned_object?.name || '';
      const tag   = [dev, iface].filter(Boolean).join(' / ');
      results.push(`IP ${ip.address}: ${tag || 'unassigned'} (${ip.status?.label || '?'})`);
    }
  }

  if (type === 'prefixes' || (type === 'auto' && isPrefix)) {
    const data = await nbGet(`ipam/prefixes/?prefix=${encodeURIComponent(query)}&limit=10`);
    for (const p of (data?.results || [])) {
      results.push(`Prefix ${p.prefix}: ${p.description || p.site?.name || ''} (${p.status?.label || '?'})`);
    }
  }

  if (type === 'auto' || type === 'devices') {
    const data = await nbGet(`dcim/devices/?q=${encodeURIComponent(query)}&limit=10`);
    for (const d of (data?.results || [])) {
      const role = d.device_role?.name || d.role?.name || '';
      const site = d.site?.name || '';
      const ip   = d.primary_ip?.address || '';
      results.push(`Device ${d.name}: ${role} | ${site}${ip ? ' | ' + ip : ''}`);
    }
  }

  if (!results.length) return `No NetBox results for: ${query}`;
  return results.join('\n');
} catch (err) {
  return `NetBox query failed: ${err.message}`;
}

