const ntopUrl = process.env.NTOPNG_URL || 'http://ntopng.universe:3005';
const token   = process.env.NTOPNG_TOKEN || '';
const authHeaders = { 'Authorization': `Token ${token}` };

async function ntopGet(path) {
  try {
    const data = await httpGet(`${ntopUrl}${path}`, authHeaders);
    return (data?.rc === 0) ? data.rsp : null;
  } catch (e) {
    return null;
  }
}

try {
  const interfaces = await ntopGet('/lua/rest/v2/get/ntopng/interfaces.lua');
  if (!interfaces || !interfaces.length) return 'ntopng unavailable or token invalid';

  const lines = ['**Fort firewall — live traffic (ntopng)**'];
  for (const iface of interfaces.slice(0, 6)) {
    const d = await ntopGet(`/lua/rest/v2/get/interface/data.lua?ifid=${iface.ifid}`);
    if (!d) continue;
    const mbps  = d.throughput_bps != null ? `${(d.throughput_bps / 1_000_000).toFixed(2)} Mbps` : 'N/A';
    const hosts = d.num_hosts  ?? d.hosts  ?? 0;
    const flows = d.num_flows  ?? d.flows  ?? 0;
    const drops = d.tot_pkt_drops ? ` | drops: ${d.tot_pkt_drops}` : '';
    lines.push(`**${iface.ifname}**: ${mbps} | ${hosts} hosts | ${flows} flows${drops}`);
  }
  return lines.join('\n');
} catch (err) {
  return `Traffic stats failed: ${err.message}`;
}

