const lokiUrl = process.env.LOKI_URL || 'http://loki.galaxy:3100';
const logqlQuery = $parameter.query;
const since = ($parameter.since || '1h').trim();
const limit = parseInt($parameter.limit || '50');

const match = since.match(/^(\d+)(s|m|h|d)$/);
const multipliers = { s: 1000, m: 60000, h: 3600000, d: 86400000 };
const offsetMs = match ? parseInt(match[1]) * (multipliers[match[2]] || 3600000) : 3600000;

const nowMs = Date.now();
const startNs = (nowMs - offsetMs).toString() + '000000';
const endNs   = nowMs.toString() + '000000';

try {
  const url = `${lokiUrl}/loki/api/v1/query_range?query=${encodeURIComponent(logqlQuery)}&start=${startNs}&end=${endNs}&limit=${limit}&direction=backward`;
  const data = await httpGet(url);
  const streams = data?.data?.result || [];

  if (!streams.length) return `No logs found for: ${logqlQuery} (last ${since})`;

  const lines = [];
  for (const stream of streams) {
    const labels = Object.entries(stream.stream || {}).map(([k,v]) => `${k}=${v}`).join(' ');
    for (const [ts, msg] of (stream.values || [])) {
      const time = new Date(Math.floor(parseInt(ts) / 1_000_000)).toISOString();
      lines.push(`[${time}] {${labels}} ${msg}`);
    }
  }
  lines.sort().reverse();
  return lines.slice(0, limit).join('\n') || 'No log entries returned';
} catch (err) {
  return `Loki query failed: ${err.message}`;
}

const WEBHOOK_URL = process.env.DISCORD_WEBHOOK_URL;
if (!WEBHOOK_URL) return 'Discord webhook URL not configured (set DISCORD_WEBHOOK_URL)';

const message = $parameter.message;
const response = await $helpers.httpRequest({
  method: 'POST',
  url: WEBHOOK_URL,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ content: message })
});
return `Posted to Discord (status: ${response.statusCode || 'ok'})`;
